diff --git a/test/modules-option.test.js b/test/modules-option.test.js
index e9ae542..0625938 100644
--- a/test/modules-option.test.js
+++ b/test/modules-option.test.js
@@ -577,4 +577,25 @@ describe('modules', () => {
     expect(stats.compilation.warnings).toMatchSnapshot('warnings');
     expect(stats.compilation.errors).toMatchSnapshot('errors');
   });
+
+  it('should avoid unnecessary "require"', async () => {
+    const config = {
+      loader: {
+        options: {
+          modules: true,
+        },
+      },
+    };
+    const testId = './modules/composes-duplicate.css';
+    const stats = await webpack(testId, config);
+    const { modules } = stats.toJson();
+    const module = modules.find((m) => m.id === testId);
+
+    expect(module.source).toMatchSnapshot('module');
+    expect(evaluated(module.source, modules)).toMatchSnapshot(
+      'module (evaluated)'
+    );
+    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
+    expect(stats.compilation.errors).toMatchSnapshot('errors');
+  });
 });

